style.css:
body {
  display: flex;
  justify-content: center;
  align-items: center;
  min-height: 100vh;
  font-size: 1.25rem;
  font-family: system-ui;
  text-align: center;
}

*,
:after,
:before {
  box-sizing: border-box;
}

.option {
  border: none;
}
.option__legend {
  display: block;
  margin-bottom: 1rem;
}
.option__fieldset {
  background-color: #fff;
  box-shadow: 0 0 1.5rem 0 rgba(0, 0, 0, 0.12);
  border-radius: 5rem;
  padding: 2rem;
  border: none;
}
.option__box {
  display: grid;
  grid-template-columns: 1fr 1fr;
  background-color: #d8f1ff;
  border-radius: 5rem;
  position: relative;
  isolation: isolate;
  padding-inline: 0.5rem;
}
.option__box:before {
  content: "";
  border-radius: 5rem;
  gap: 1rem;
  border: 4px solid #fff;
  background-color: #97dbff;
  position: absolute;
  inset: 0;
  width: calc(50% + 0.5rem);
  margin-block: -6px;
  z-index: -1;
  transition: transform 0.2s cubic-bezier(0.66, -0.33, 0.33, 1.33);
}
:has([value=no]:checked) .option__box:before {
  transform: translateX(calc(100% - 1rem));
}
.option__radio {
  text-align: center;
  padding: 1rem 2rem;
  position: relative;
  display: flex;
  gap: 0.5rem;
}
.option__input {
  outline-offset: 0.5rem;
  outline-color: currentColor;
  cursor: pointer;
  position: absolute;
  inset: 0;
  border-radius: 5rem;
  appearance: none;
  margin: 0;
  padding: 0;
}
